class Solution {
    public int minimizedStringLength(String s) {
        int[] count = new int[26];
        for (char c : s.toCharArray()) {
            count[c - 'a']++;
        }
        int result = 0;
        for (int i = 0; i < 26; i++) {
            if (count[i] > 0) {
                result += count[i] % 2;
            }
        }
        return result + (s.length() - result) / 2 * 2;
    }
}
